var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CN No. VCDF002S07056-10\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n부록: 시국 도서관 기밀 자료 열람 기록","JPN":"CN No. VCDF002S07056-10\\n<color=#ffd34c>2級要因</color> 閲覧承認資料\\n付録: 時局図書館機密資料閲覧記録","ENG":"(ENG)CN No. VCDF002S07056-10\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n부록: 시국 도서관 기밀 자료 열람 기록","TWN":"(TWN)CN No. VCDF002S07056-10\\n<color=#ffd34c>2급 요인</color> 열람 승인 자료\\n부록: 시국 도서관 기밀 자료 열람 기록"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"부탁하신 자료입니다.","JPN":"お願いした資料です。","ENG":"(ENG)부탁하신 자료입니다.","TWN":"(TWN)부탁하신 자료입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"아, 감사합니다. 역시 꼼꼼하게 정리되어 있군요.","JPN":"あ、感謝します。やはり几帳面に整理されていますね。","ENG":"(ENG)아, 감사합니다. 역시 꼼꼼하게 정리되어 있군요.","TWN":"(TWN)아, 감사합니다. 역시 꼼꼼하게 정리되어 있군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"그런데 조사관님 같은 분이 넬슨 자매님은 무슨 일로......?","JPN":"ところで調査官様のような方がネルソン姉妹様は何のイーロ......?","ENG":"(ENG)그런데 조사관님 같은 분이 넬슨 자매님은 무슨 일로......?","TWN":"(TWN)그런데 조사관님 같은 분이 넬슨 자매님은 무슨 일로......?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"아는 사이십니까?","JPN":"知り合いですか?","ENG":"(ENG)아는 사이십니까?","TWN":"(TWN)아는 사이십니까?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"처음 시국에 왔을 때는 꽤 유명했습니다. 시성 안건이 거론됐으니까요.","JPN":"初めて時局に来た時はかなり有名でした。詩聖案件が挙論されたからです。","ENG":"(ENG)처음 시국에 왔을 때는 꽤 유명했습니다. 시성 안건이 거론됐으니까요.","TWN":"(TWN)처음 시국에 왔을 때는 꽤 유명했습니다. 시성 안건이 거론됐으니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"시성 안건이요? 열일곱 살인데?","JPN":"詩聖案件です?十七歳だが?","ENG":"(ENG)시성 안건이요? 열일곱 살인데?","TWN":"(TWN)시성 안건이요? 열일곱 살인데?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"네. 시국의 공기가 잔잔하다지만 그 정도면 시끄러워질 만도 하죠.","JPN":"はい。時局の空気が穏やかといえどもそのチョン図面うるさくなるに値します。","ENG":"(ENG)네. 시국의 공기가 잔잔하다지만 그 정도면 시끄러워질 만도 하죠.","TWN":"(TWN)네. 시국의 공기가 잔잔하다지만 그 정도면 시끄러워질 만도 하죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"본인이 거절해서 유야무야되긴 했습니다만.","JPN":"本人が断って有耶無耶されたりしたのですが。","ENG":"(ENG)본인이 거절해서 유야무야되긴 했습니다만.","TWN":"(TWN)본인이 거절해서 유야무야되긴 했습니다만."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"시성 안건에 제출된 자료는요?","JPN":"詩聖案件に提出された資料は?","ENG":"(ENG)시성 안건에 제출된 자료는요?","TWN":"(TWN)시성 안건에 제출된 자료는요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"방금 드린 것 중에 있습니다. 네, 그거요.","JPN":"今差し上げたこと中にあります。はい、それです。","ENG":"(ENG)방금 드린 것 중에 있습니다. 네, 그거요.","TWN":"(TWN)방금 드린 것 중에 있습니다. 네, 그거요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"이 사건이군요. 카운터로 각성하기 이전이네요. 산사태에서 민간인들을 보호했다, 라......","JPN":"この事件ですね。カウンターで目覚める以前ですね。山崩れで民間人を保護した、ラ......","ENG":"(ENG)이 사건이군요. 카운터로 각성하기 이전이네요. 산사태에서 민간인들을 보호했다, 라......","TWN":"(TWN)이 사건이군요. 카운터로 각성하기 이전이네요. 산사태에서 민간인들을 보호했다, 라......"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"███년 ██월 ██일. 스코틀랜드 ██████시 ██터널.","JPN":"███年██月██日。スコットランド██████時██トンネル。","ENG":"(ENG)███년 ██월 ██일. 스코틀랜드 ██████시 ██터널.","TWN":"(TWN)███년 ██월 ██일. 스코틀랜드 ██████시 ██터널."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"오후 5시 32분 경. 국지성 집중 호우로 인한 산사태 발생.","JPN":"午後5時32分頃。局地性集中豪雨による山崩れ発生。","ENG":"(ENG)오후 5시 32분 경. 국지성 집중 호우로 인한 산사태 발생.","TWN":"(TWN)오후 5시 32분 경. 국지성 집중 호우로 인한 산사태 발생."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"오후 5시 34분 경. 시 일대에 긴급 대피령 발령.","JPN":"午後5時34分頃。時一帯に緊急待避令発令。","ENG":"(ENG)오후 5시 34분 경. 시 일대에 긴급 대피령 발령.","TWN":"(TWN)오후 5시 34분 경. 시 일대에 긴급 대피령 발령."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"오후 5시 35분 경. 유출된 암석과 토사에 터널 붕괴 및 매몰.","JPN":"午後5時35分頃。流出した岩石と土砂にトンネル崩壊及び埋没。","ENG":"(ENG)오후 5시 35분 경. 유출된 암석과 토사에 터널 붕괴 및 매몰.","TWN":"(TWN)오후 5시 35분 경. 유출된 암석과 토사에 터널 붕괴 및 매몰."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"오후 7시 47분 경. 주 정부 구조대 편성 후 즉각 파견. 의회 재난 대책 위원회 소집.","JPN":"午後7時47分頃。州政府救助隊編成後即刻派遣。議会災難対策委員会召集。","ENG":"(ENG)오후 7시 47분 경. 주 정부 구조대 편성 후 즉각 파견. 의회 재난 대책 위원회 소집.","TWN":"(TWN)오후 7시 47분 경. 주 정부 구조대 편성 후 즉각 파견. 의회 재난 대책 위원회 소집."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"보름 동안 매몰자들을 수색했다.......","JPN":"半月間埋没者を捜索した.......","ENG":"(ENG)보름 동안 매몰자들을 수색했다.......","TWN":"(TWN)보름 동안 매몰자들을 수색했다......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"아, 기억납니다. 이 사건.","JPN":"あ、思い出します。この事件。","ENG":"(ENG)아, 기억납니다. 이 사건.","TWN":"(TWN)아, 기억납니다. 이 사건."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"죽은 줄 알았던 매몰자 상당수가 생존해서 떠들썩했었죠. 나중에 시가지 지하에서 일어난 침식 현상 때문이라고 밝혀졌다던데.","JPN":"死んだと思った埋没者相当数が生存して騒がしかったです。後で市街地地下で起きた侵食現象のためと明かされたようだが。","ENG":"(ENG)죽은 줄 알았던 매몰자 상당수가 생존해서 떠들썩했었죠. 나중에 시가지 지하에서 일어난 침식 현상 때문이라고 밝혀졌다던데.","TWN":"(TWN)죽은 줄 알았던 매몰자 상당수가 생존해서 떠들썩했었죠. 나중에 시가지 지하에서 일어난 침식 현상 때문이라고 밝혀졌다던데."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"넬슨 자매님이 보호했다고 하더군요. 보름 동안 흙더미 밑에 갇혀 있던 생존자들이 증언했습니다.","JPN":"ネルソン姉妹様が保護したと言いますね。半月間土盛り下に閉じ込められていた生存者が証言しました。","ENG":"(ENG)넬슨 자매님이 보호했다고 하더군요. 보름 동안 흙더미 밑에 갇혀 있던 생존자들이 증언했습니다.","TWN":"(TWN)넬슨 자매님이 보호했다고 하더군요. 보름 동안 흙더미 밑에 갇혀 있던 생존자들이 증언했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"그 어린 자매가?","JPN":"その幼い姉妹家?","ENG":"(ENG)그 어린 자매가?","TWN":"(TWN)그 어린 자매가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"네. 넬슨 자매가 부상자들을 돌봐 주고 자기들을 안심시켜 주지 않았더라면 못 버텼을 거라더군요.","JPN":"はい。ネルソン姉妹が部ボックスを面倒を見てくれて自分を安心させてくれなかったら堪えることができなかったことだと言う。","ENG":"(ENG)네. 넬슨 자매가 부상자들을 돌봐 주고 자기들을 안심시켜 주지 않았더라면 못 버텼을 거라더군요.","TWN":"(TWN)네. 넬슨 자매가 부상자들을 돌봐 주고 자기들을 안심시켜 주지 않았더라면 못 버텼을 거라더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"다들 인터뷰에서 그때 들은 찬송이 가장 고마웠다고 했습니다.","JPN":"みんなインタビューであの時は賛美が最もありがたかったと言いました。","ENG":"(ENG)다들 인터뷰에서 그때 들은 찬송이 가장 고마웠다고 했습니다.","TWN":"(TWN)다들 인터뷰에서 그때 들은 찬송이 가장 고마웠다고 했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"흐음.......","JPN":"フウム.......","ENG":"(ENG)흐음.......","TWN":"(TWN)흐음......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"참 세상 돌아가는 게 얄궂습니다. 좋은 일 하는 바람에 3과 같은 곳으로 와 버렸다니.","JPN":"本当に世の中帰るのが奇妙です。良い働くせいで3のような所に来てしまったなんて。","ENG":"(ENG)참 세상 돌아가는 게 얄궂습니다. 좋은 일 하는 바람에 3과 같은 곳으로 와 버렸다니.","TWN":"(TWN)참 세상 돌아가는 게 얄궂습니다. 좋은 일 하는 바람에 3과 같은 곳으로 와 버렸다니."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLERK_VOICE_NULL_NULL","text":{"KOREA":"네?","JPN":"はい?","ENG":"(ENG)네?","TWN":"(TWN)네?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INSPECTOR_VOICE_NULL_NULL","text":{"KOREA":"별 얘기 아닙니다. 협조해 줘서 고마워요.\\n가기 전에 미리 알아 둘 게 있었거든요.","JPN":"別に話ではないです。協調してくれてありがとう。\\n行く前にあらかじめ分かることがあったんですよ。","ENG":"(ENG)별 얘기 아닙니다. 협조해 줘서 고마워요.\\n가기 전에 미리 알아 둘 게 있었거든요.","TWN":"(TWN)별 얘기 아닙니다. 협조해 줘서 고마워요.\\n가기 전에 미리 알아 둘 게 있었거든요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};